/**
 * Calculates an estimated daily dietary toxin exposure score.
 * Input factors are weighted based on typical contaminant levels and frequencies.
 */
function calculateToxinExposure(inputs) {
  // Constants for weighting various toxin sources
  const MERCURY_FACTORS = {
    'Low': 1,
    'Medium': 3,
    'High': 8
  };
  const RED_MEAT_FACTOR = 0.7;
  const NON_ORGANIC_PRODUCE_FACTOR = 0.8;
  const ULTRA_PROCESSED_FACTOR = 0.9;
  const TAP_WATER_FACTOR = 0.4;
  const HIGH_TEMP_COOKING_FACTOR = 1.2;
  const PLASTIC_HEATING_FACTOR = 1.5;

  // Ensure inputs are numbers and handle potential undefined/null by defaulting to 0
  const red_meat_servings_weekly = Number(inputs.red_meat_processed_servings_weekly || 0);
  const fish_servings_weekly = Number(inputs.fish_servings_weekly || 0);
  const non_organic_fruit_veg_servings_daily = Number(inputs.non_organic_fruit_veg_servings_daily || 0);
  const ultra_processed_food_servings_daily = Number(inputs.ultra_processed_food_servings_daily || 0);
  const tap_water_unfiltered_liters_daily = Number(inputs.tap_water_unfiltered_liters_daily || 0);
  const high_temp_cooking_frequency_weekly = Number(inputs.high_temp_cooking_frequency_weekly || 0);
  const food_heated_in_plastic_frequency_weekly = Number(inputs.food_heated_in_plastic_frequency_weekly || 0);
  const fish_mercury_level = inputs.fish_mercury_level || 'Low'; // Default to Low if not provided

  // 1. Calculate component scores (some weekly, some daily)
  const red_meat_score_weekly = red_meat_servings_weekly * RED_MEAT_FACTOR;
  const heavy_metal_score_weekly = fish_servings_weekly * (MERCURY_FACTORS[fish_mercury_level] || MERCURY_FACTORS['Low']);
  const pesticide_score_daily = non_organic_fruit_veg_servings_daily * NON_ORGANIC_PRODUCE_FACTOR;
  const processed_additive_score_daily = ultra_processed_food_servings_daily * ULTRA_PROCESSED_FACTOR;
  const water_contaminant_score_daily = tap_water_unfiltered_liters_daily * TAP_WATER_FACTOR;
  const cooking_contaminant_score_weekly = high_temp_cooking_frequency_weekly * HIGH_TEMP_COOKING_FACTOR;
  const plastic_leaching_score_weekly = food_heated_in_plastic_frequency_weekly * PLASTIC_HEATING_FACTOR;

  // 2. Convert weekly scores to daily equivalents for summation
  const daily_red_meat_score = red_meat_score_weekly / 7;
  const daily_heavy_metal_score = heavy_metal_score_weekly / 7;
  const daily_cooking_contaminant_score = cooking_contaminant_score_weekly / 7;
  const daily_plastic_leaching_score = plastic_leaching_score_weekly / 7;

  // 3. Sum all daily component scores for a total raw daily toxin load
  const total_daily_raw_score = 
    daily_red_meat_score +
    daily_heavy_metal_score +
    pesticide_score_daily +
    processed_additive_score_daily +
    water_contaminant_score_daily +
    daily_cooking_contaminant_score +
    daily_plastic_leaching_score;

  // 4. Define a theoretical maximum raw score for normalization (based on max inputs)
  // Max inputs: 14 processed red meat, 10 high mercury fish, 15 non-organic fruit/veg,
  // 10 ultra-processed, 5L unfiltered water, 14 high temp cooking, 14 plastic heating.
  const MAX_RAW_SCORE = 
    (14 * RED_MEAT_FACTOR / 7) +               // Max daily red meat
    (10 * MERCURY_FACTORS['High'] / 7) +       // Max daily heavy metal
    (15 * NON_ORGANIC_PRODUCE_FACTOR) +      // Max daily pesticide
    (10 * ULTRA_PROCESSED_FACTOR) +          // Max daily processed additive
    (5 * TAP_WATER_FACTOR) +                 // Max daily water contaminant
    (14 * HIGH_TEMP_COOKING_FACTOR / 7) +    // Max daily cooking contaminant
    (14 * PLASTIC_HEATING_FACTOR / 7);       // Max daily plastic leaching

  // 5. Normalize the total raw daily toxin load to a score between 0 and 100
  // Ensure score doesn't exceed 100 or go below 0
  let normalized_score = (total_daily_raw_score / MAX_RAW_SCORE) * 100;
  normalized_score = Math.min(100, Math.max(0, normalized_score));

  return {
    daily_estimated_toxin_load_score: normalized_score,
    daily_pesticide_score: pesticide_score_daily,
    daily_heavy_metal_score: daily_heavy_metal_score,
    daily_processed_additive_score: processed_additive_score_daily + daily_red_meat_score + water_contaminant_score_daily + daily_cooking_contaminant_score + daily_plastic_leaching_score
  };
}
